import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.granola.ai/introduction";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeL";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Granola API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:granola",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const granolaFirewall = {",
    '  name: "granola",',
    '  description: "Granola API",',
    "  placeholders: {",
    `    GRANOLA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://public-api.granola.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.GRANOLA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Granola firewall config...");
  const ts = generateTypeScript();
  writeOutput("granola", ts, import.meta.dirname);
}
